#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define ETA 0.3f
#define MOMENTUM 0.3f
#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16

__kernel void bpnn_layerforward_ocl(__global float* input_units,
                                   __global float* hidden_units,
                                   __global float* input_weights,
                                   __global float* hidden_partial_sum,
                                   __local float* lsum,
                                   __local float* lweights,
                                   const int input_n,
                                   const int hidden_n)
{
    int tx = get_local_id(0);
    int ty = get_local_id(1);
    int bx = get_group_id(0);
    int by = get_group_id(1);

    int row = bx * BLOCK_SIZE + tx; // input index
    int col = by * BLOCK_SIZE + ty; // hidden index

    // Each work-group computes a BLOCK_SIZE x BLOCK_SIZE tile of the output matrix

    // Load input units into local memory
    __local float linput[BLOCK_SIZE+1];
    if (ty == 0 && (row <= input_n)) {
        linput[tx] = input_units[row];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Load weights tile into local memory
    if ((row <= input_n) && (col <= hidden_n)) {
        int idx = row * (hidden_n + 1) + col;
        lweights[tx * BLOCK_SIZE + ty] = input_weights[idx];
    } else {
        lweights[tx * BLOCK_SIZE + ty] = 0.0f;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    if (col <= hidden_n) {
        for (int i = 0; i < BLOCK_SIZE; i++) {
            int input_idx = bx * BLOCK_SIZE + i;
            if (input_idx <= input_n) {
                sum += lweights[i * BLOCK_SIZE + ty] * linput[i];
            }
        }
    }

    // Store partial sums in global memory
    if ((row <= input_n) && (col <= hidden_n)) {
        int partial_idx = bx * get_num_groups(1) * BLOCK_SIZE + by * BLOCK_SIZE + ty;
        hidden_partial_sum[partial_idx] = sum;
    }
}

__kernel void bpnn_adjust_weights_ocl(__global float* delta,
                                     const int ndelta,
                                     __global float* ly,
                                     const int nly,
                                     __global float* w,
                                     __global float* oldw)
{
    int j = get_global_id(0) + 1; // delta index
    int k = get_global_id(1);     // ly index

    if (j <= ndelta && k <= nly) {
        int idx = k * (ndelta + 1) + j;
        float new_dw = ETA * delta[j] * ly[k] + MOMENTUM * oldw[idx];
        w[idx] += new_dw;
        oldw[idx] = new_dw;
    }
}
